1	-------------------------------------------------------------------------------
2	-- Company    : SLAC National Accelerator Laboratory
3	-------------------------------------------------------------------------------
4	-- Description: IPv4 RX Engine Module
5	-- Note: IPv4 checksum checked in EthMac core
6	-------------------------------------------------------------------------------
7	-- This file is part of 'SLAC Firmware Standard Library'.
8	-- It is subject to the license terms in the LICENSE.txt file found in the
9	-- top-level directory of this distribution and at:
10	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
11	-- No part of 'SLAC Firmware Standard Library', including this file,
12	-- may be copied, modified, propagated, or distributed except according to
13	-- the terms contained in the LICENSE.txt file.
14	-------------------------------------------------------------------------------
15	
16	library ieee;
17	use ieee.std_logic_1164.all;
18	use ieee.std_logic_unsigned.all;
19	use ieee.std_logic_arith.all;
20	
21	library surf;
22	use surf.StdRtlPkg.all;
23	use surf.AxiStreamPkg.all;
24	use surf.SsiPkg.all;
25	use surf.EthMacPkg.all;
26	
27	entity IpV4EngineRx is
28	   generic (
29	      TPD_G            : time      := 1 ns;
30	      RST_POLARITY_G   : sl        := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
31	      RST_ASYNC_G      : boolean   := false;
32	      SIM_ERROR_HALT_G : boolean   := false;
33	      PROTOCOL_SIZE_G  : positive  := 1;
34	      PROTOCOL_G       : Slv8Array := (0 => UDP_C));
35	   port (
36	      -- Interface to Ethernet Frame MUX/DEMUX
37	      ibIpv4Master      : in  AxiStreamMasterType;
38	      ibIpv4Slave       : out AxiStreamSlaveType;
39	      localhostMaster   : in  AxiStreamMasterType;
40	      localhostSlave    : out AxiStreamSlaveType;
41	      -- Interface to Protocol Engine
42	      ibProtocolMasters : out AxiStreamMasterArray(PROTOCOL_SIZE_G-1 downto 0);
43	      ibProtocolSlaves  : in  AxiStreamSlaveArray(PROTOCOL_SIZE_G-1 downto 0);
44	      -- Clock and Reset
45	      clk               : in  sl;
46	      rst               : in  sl);
47	end IpV4EngineRx;
48	
49	architecture rtl of IpV4EngineRx is
50	
51	   type StateType is (
52	      IDLE_S,
53	      IPV4_HDR0_S,
54	      IPV4_HDR1_S,
55	      IPV4_HDR2_S,
56	      MOVE_S,
57	      LAST_S);
58	
59	   type RegType is record
60	      tLast    : sl;
61	      eofe     : sl;
62	      len      : slv(15 downto 0);
63	      protocol : slv(7 downto 0);
64	      tKeep    : slv(15 downto 0);
65	      tData    : slv(127 downto 0);
66	      rxSlave  : AxiStreamSlaveType;
67	      txMaster : AxiStreamMasterType;
68	      state    : StateType;
69	   end record RegType;
70	   constant REG_INIT_C : RegType := (
71	      tLast    => '0',
72	      eofe     => '0',
73	      len      => (others => '0'),
74	      protocol => (others => '0'),
75	      tKeep    => (others => '0'),
76	      tData    => (others => '0'),
77	      rxSlave  => AXI_STREAM_SLAVE_INIT_C,
78	      txMaster => AXI_STREAM_MASTER_INIT_C,
79	      state    => IDLE_S);
80	
81	   signal r   : RegType := REG_INIT_C;
82	   signal rin : RegType;
83	
84	   signal rxMaster : AxiStreamMasterType;
85	   signal rxSlave  : AxiStreamSlaveType;
86	   signal txSlave  : AxiStreamSlaveType;
87	
88	   -- attribute dont_touch              : string;
89	   -- attribute dont_touch of r         : signal is "TRUE";
90	
91	begin
92	
93	   U_Mux : entity surf.AxiStreamMux
94	      generic map (
95	         TPD_G          => TPD_G,
96	         RST_POLARITY_G => RST_POLARITY_G,
97	         RST_ASYNC_G    => RST_ASYNC_G,
98	         PIPE_STAGES_G  => 0,
99	         NUM_SLAVES_G   => 2)
100	      port map (
101	         -- Clock and reset
102	         axisClk         => clk,
103	         axisRst         => rst,
104	         -- Slaves
105	         sAxisMasters(0) => ibIpv4Master,
106	         sAxisMasters(1) => localhostMaster,
107	         sAxisSlaves(0)  => ibIpv4Slave,
108	         sAxisSlaves(1)  => localhostSlave,
109	         -- Master
110	         mAxisMaster     => rxMaster,
111	         mAxisSlave      => rxSlave);
112	
113	   comb : process (r, rst, rxMaster, txSlave) is
114	      variable v : RegType;
115	   begin
116	      -- Latch the current value
117	      v := r;
118	
119	      -- Reset the flags
120	      v.rxSlave := AXI_STREAM_SLAVE_INIT_C;
121	      if (txSlave.tReady = '1') then
122	         v.txMaster.tValid := '0';
123	         v.txMaster.tLast  := '0';
124	         v.txMaster.tUser  := (others => '0');
125	         v.txMaster.tKeep  := (others => '1');
126	      end if;
127	
128	      -- State Machine
129	      case r.state is
130	         ----------------------------------------------------------------------
131	         when IDLE_S =>
132	            -- Check for data
133	            if (rxMaster.tValid = '1') and (v.txMaster.tValid = '0') then
134	               -- Accept the data
135	               v.rxSlave.tReady := '1';
136	               -- Check for SOF with no EOF
137	               if (ssiGetUserSof(EMAC_AXIS_CONFIG_C, rxMaster) = '1') and (rxMaster.tLast = '0') then
138	                  -- Latch the remote MAC address
139	                  v.txMaster.tData(47 downto 0)  := rxMaster.tData(95 downto 48);
140	                  -- Unused data field
141	                  v.txMaster.tData(63 downto 48) := (others => '0');
142	                  -- Next state
143	                  v.state                        := IPV4_HDR0_S;
144	               end if;
145	            end if;
146	         ----------------------------------------------------------------------
147	         when IPV4_HDR0_S =>
148	            -- Check for data
149	            if (rxMaster.tValid = '1') and (v.txMaster.tValid = '0') then
150	               -- Accept the data
151	               v.rxSlave.tReady                := '1';
152	               -- Calculate the IPV4 Pseudo Header length (in little Endian)
153	               v.len(15 downto 8)              := rxMaster.tData(7 downto 0);  -- IPV4_Length(15 downto 8)
154	               v.len(7 downto 0)               := rxMaster.tData(15 downto 8);  -- IPV4_Length(7 downto 0)
155	               v.len                           := v.len - 20;  -- IPV4 Pseudo Header's length = protocol length - 20 Bytes
156	               -- Latch the protocol value
157	               v.protocol                      := rxMaster.tData(63 downto 56);
158	               -- Source IP Address(31 downto 0)
159	               v.txMaster.tData(95 downto 64)  := rxMaster.tData(111 downto 80);
160	               -- Destination IP Address(31 downto 16)
161	               v.txMaster.tData(111 downto 96) := rxMaster.tData(127 downto 112);
162	               -- Next state if protocol not detected during the "for loop"
163	               v.state                         := IDLE_S;
164	               -- Loop through the protocol buses
165	               for i in (PROTOCOL_SIZE_G-1) downto 0 loop
166	                  if (v.protocol = PROTOCOL_G(i)) then
167	                     -- Latch the protocol bus pointer
168	                     v.txMaster.tDest := toSlv(i, 8);
169	                     -- Next state if protocol not detected
170	                     v.state          := IPV4_HDR1_S;
171	                  end if;
172	               end loop;
173	            end if;
174	         ----------------------------------------------------------------------
175	         when IPV4_HDR1_S =>
176	            -- Check for data
177	            if (rxMaster.tValid = '1') and (v.txMaster.tValid = '0') then
178	               -- Move the data
179	               v.txMaster.tValid                := '1';
180	               -- Set the SOF
181	               ssiSetUserSof(EMAC_AXIS_CONFIG_C, v.txMaster, '1');
182	               -- Destination IP Address(15 downto 0)
183	               v.txMaster.tData(127 downto 112) := rxMaster.tData(15 downto 0);
184	               -- Track the leftovers
185	               v.tData(7 downto 0)              := x"00";
186	               v.tData(15 downto 8)             := r.protocol;
187	               v.tData(23 downto 16)            := r.len(15 downto 8);
188	               v.tData(31 downto 24)            := r.len(7 downto 0);
189	               v.tData(127 downto 32)           := rxMaster.tData(111 downto 16);
190	               v.tKeep(3 downto 0)              := "1111";
191	               v.tKeep(15 downto 4)             := rxMaster.tKeep(13 downto 2);
192	               v.tLast                          := rxMaster.tLast;
193	               v.eofe                           := ssiGetUserEofe(EMAC_AXIS_CONFIG_C, rxMaster);
194	               -- Check for no remainder
195	               if (rxMaster.tKeep(15 downto 14) = 0) then
196	                  -- Accept the data
197	                  v.rxSlave.tReady := '1';
198	                  -- Next state
199	                  v.state          := LAST_S;
200	               else
201	                  -- Next state
202	                  v.state := IPV4_HDR2_S;
203	               end if;
204	            end if;
205	         ----------------------------------------------------------------------
206	         when IPV4_HDR2_S =>
207	            -- Check for data
208	            if (rxMaster.tValid = '1') and (v.txMaster.tValid = '0') then
209	               -- Accept the data
210	               v.rxSlave.tReady               := '1';
211	               -- Move the data
212	               v.txMaster.tValid              := '1';
213	               v.txMaster.tData(127 downto 0) := r.tData;
214	               v.txMaster.tKeep(15 downto 0)  := r.tKeep;
215	               -- Track the leftovers
216	               v.tData(15 downto 0)           := rxMaster.tData(127 downto 112);
217	               v.tKeep(1 downto 0)            := rxMaster.tKeep(15 downto 14);
218	               v.tKeep(15 downto 2)           := (others => '0');
219	               v.tLast                        := rxMaster.tLast;
220	               v.eofe                         := ssiGetUserEofe(EMAC_AXIS_CONFIG_C, rxMaster);
221	               -- Check for EOF
222	               if (rxMaster.tLast = '1') then
223	                  -- Check the leftovers
224	                  if (v.tKeep /= 0) then
225	                     -- Next state
226	                     v.state := LAST_S;
227	                  else
228	                     -- Set EOF and EOFE
229	                     v.txMaster.tLast := '1';
230	                     ssiSetUserEofe(EMAC_AXIS_CONFIG_C, v.txMaster, v.eofe);
231	                     -- Next state
232	                     v.state          := IDLE_S;
233	                  end if;
234	               else
235	                  -- Next state
236	                  v.state := MOVE_S;
237	               end if;
238	            end if;
239	         ----------------------------------------------------------------------
240	         when MOVE_S =>
241	            -- Check for data
242	            if (rxMaster.tValid = '1') and (v.txMaster.tValid = '0') then
243	               -- Accept the data
244	               v.rxSlave.tReady                := '1';
245	               -- Move the data
246	               v.txMaster.tValid               := '1';
247	               -- Move the data
248	               v.txMaster.tData(15 downto 0)   := r.tData(15 downto 0);
249	               v.txMaster.tData(127 downto 16) := rxMaster.tData(111 downto 0);
250	               v.txMaster.tKeep(1 downto 0)    := r.tKeep(1 downto 0);
251	               v.txMaster.tKeep(15 downto 2)   := rxMaster.tKeep(13 downto 0);
252	               -- Track the leftovers
253	               v.tData(15 downto 0)            := rxMaster.tData(127 downto 112);
254	               v.tKeep(1 downto 0)             := rxMaster.tKeep(15 downto 14);
255	               v.tLast                         := rxMaster.tLast;
256	               v.eofe                          := ssiGetUserEofe(EMAC_AXIS_CONFIG_C, rxMaster);
257	               -- Check for tLast
258	               if (v.tLast = '1') then
259	                  -- Check the leftover tKeep is not empty
260	                  if (v.tKeep /= 0) then
261	                     -- Next state
262	                     v.state := LAST_S;
263	                  else
264	                     -- Set EOF and EOFE
265	                     v.txMaster.tLast := '1';
266	                     ssiSetUserEofe(EMAC_AXIS_CONFIG_C, v.txMaster, v.eofe);
267	                     -- Next state
268	                     v.state          := IDLE_S;
269	                  end if;
270	               end if;
271	            end if;
272	         ----------------------------------------------------------------------
273	         when LAST_S =>
274	            -- Check for data
275	            if (v.txMaster.tValid = '0') then
276	               -- Move the data
277	               v.txMaster.tValid              := '1';
278	               v.txMaster.tData(127 downto 0) := r.tData;
279	               v.txMaster.tKeep(15 downto 0)  := r.tKeep;
280	               v.txMaster.tLast               := '1';
281	               ssiSetUserEofe(EMAC_AXIS_CONFIG_C, v.txMaster, r.eofe);
282	               -- Next state
283	               v.state                        := IDLE_S;
284	            end if;
285	      ----------------------------------------------------------------------
286	      end case;
287	
288	      -- Combinatorial outputs before the reset
289	      rxSlave <= v.rxSlave;
290	
291	      -- Reset
292	      if (RST_ASYNC_G = false and rst = RST_POLARITY_G) then
293	         v := REG_INIT_C;
294	      end if;
295	
296	      -- Register the variable for next clock cycle
297	      rin <= v;
298	
299	   end process comb;
300	
301	   seq : process (clk, rst) is
302	   begin
303	      if (RST_ASYNC_G and rst = RST_POLARITY_G) then
304	         r <= REG_INIT_C after TPD_G;
305	      elsif rising_edge(clk) then
306	         r <= rin after TPD_G;
307	      end if;
308	   end process seq;
309	
310	   U_AxisMux : entity surf.AxiStreamDeMux
311	      generic map (
312	         TPD_G          => TPD_G,
313	         RST_POLARITY_G => RST_POLARITY_G,
314	         RST_ASYNC_G    => RST_ASYNC_G,
315	         PIPE_STAGES_G  => 1,
316	         NUM_MASTERS_G  => PROTOCOL_SIZE_G)
317	      port map (
318	         -- Clock and reset
319	         axisClk      => clk,
320	         axisRst      => rst,
321	         -- Slave
322	         sAxisMaster  => r.txMaster,
323	         sAxisSlave   => txSlave,
324	         -- Masters
325	         mAxisMasters => ibProtocolMasters,
326	         mAxisSlaves  => ibProtocolSlaves);
327	
328	end rtl;
329

