1	-------------------------------------------------------------------------------
2	-- Company    : SLAC National Accelerator Laboratory
3	-------------------------------------------------------------------------------
4	-- Description: ARP Engine
5	-------------------------------------------------------------------------------
6	-- This file is part of 'SLAC Firmware Standard Library'.
7	-- It is subject to the license terms in the LICENSE.txt file found in the
8	-- top-level directory of this distribution and at:
9	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
10	-- No part of 'SLAC Firmware Standard Library', including this file,
11	-- may be copied, modified, propagated, or distributed except according to
12	-- the terms contained in the LICENSE.txt file.
13	-------------------------------------------------------------------------------
14	
15	library ieee;
16	use ieee.std_logic_1164.all;
17	use ieee.std_logic_unsigned.all;
18	use ieee.std_logic_arith.all;
19	
20	library surf;
21	use surf.StdRtlPkg.all;
22	use surf.AxiStreamPkg.all;
23	use surf.SsiPkg.all;
24	use surf.EthMacPkg.all;
25	
26	entity ArpEngine is
27	   generic (
28	      TPD_G          : time     := 1 ns;
29	      RST_POLARITY_G : sl       := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
30	      RST_ASYNC_G    : boolean  := false;
31	      CLIENT_SIZE_G  : positive := 1;
32	      CLK_FREQ_G     : real     := 156.25E+06);  -- In units of Hz
33	   port (
34	      -- Local Configuration
35	      localMac      : in  slv(47 downto 0);
36	      localIp       : in  slv(31 downto 0);
37	      -- Interface to Client Engine(s)
38	      arpReqMasters : in  AxiStreamMasterArray(CLIENT_SIZE_G-1 downto 0);  -- Request via IP address
39	      arpReqSlaves  : out AxiStreamSlaveArray(CLIENT_SIZE_G-1 downto 0);
40	      arpAckMasters : out AxiStreamMasterArray(CLIENT_SIZE_G-1 downto 0);  -- Respond with MAC address
41	      arpAckSlaves  : in  AxiStreamSlaveArray(CLIENT_SIZE_G-1 downto 0);
42	      -- Interface to Ethernet Frame MUX/DEMUX
43	      ibArpMaster   : in  AxiStreamMasterType;
44	      ibArpSlave    : out AxiStreamSlaveType;
45	      obArpMaster   : out AxiStreamMasterType;
46	      obArpSlave    : in  AxiStreamSlaveType;
47	      -- Clock and Reset
48	      clk           : in  sl;
49	      rst           : in  sl);
50	end ArpEngine;
51	
52	architecture rtl of ArpEngine is
53	
54	   -- ARP Constants
55	   constant BROADCAST_MAC_C  : slv(47 downto 0) := (others => '1');
56	   constant HARDWWARE_TYPE_C : slv(15 downto 0) := x"0100";  -- HardwareType = ETH = 0x0001
57	   constant PROTOCOL_TYPE_C  : slv(15 downto 0) := x"0008";  -- ProtocolType = IP  = 0x0800
58	   constant HARDWWARE_LEN_C  : slv(7 downto 0)  := x"06";  -- HardwareLength = 6 (6 Bytes/MAC)
59	   constant PROTOCOL_LEN_C   : slv(7 downto 0)  := x"04";  -- ProtocolLength = 4 (6 Bytes/IP)
60	   constant ARP_REQ_C        : slv(15 downto 0) := x"0100";  -- OpCode = ARP Request  = 0x0001
61	   constant ARP_REPLY_C      : slv(15 downto 0) := x"0200";  -- OpCode = ARP Reply    = 0x0002
62	   constant TIMER_1_SEC_C    : natural          := getTimeRatio(CLK_FREQ_G, 1.0);
63	
64	   type StateType is (
65	      IDLE_S,
66	      RX_S,
67	      CHECK_S,
68	      SCAN_S,
69	      TX_S);
70	
71	   type RegType is record
72	      cnt           : natural range 0 to 3;
73	      tData         : Slv128Array(2 downto 0);
74	      ibArpSlave    : AxiStreamSlaveType;
75	      txArpMaster   : AxiStreamMasterType;
76	      arpReqSlaves  : AxiStreamSlaveArray(CLIENT_SIZE_G-1 downto 0);
77	      arpAckMasters : AxiStreamMasterArray(CLIENT_SIZE_G-1 downto 0);
78	      arpTimers     : NaturalArray(CLIENT_SIZE_G-1 downto 0);
79	      reqCnt        : natural range 0 to CLIENT_SIZE_G-1;
80	      ackCnt        : natural range 0 to CLIENT_SIZE_G-1;
81	      state         : StateType;
82	   end record RegType;
83	   constant REG_INIT_C : RegType := (
84	      cnt           => 0,
85	      tData         => (others => (others => '0')),
86	      ibArpSlave    => AXI_STREAM_SLAVE_INIT_C,
87	      txArpMaster   => AXI_STREAM_MASTER_INIT_C,
88	      arpReqSlaves  => (others => AXI_STREAM_SLAVE_INIT_C),
89	      arpAckMasters => (others => AXI_STREAM_MASTER_INIT_C),
90	      arpTimers     => (others => 0),
91	      reqCnt        => 0,
92	      ackCnt        => 0,
93	      state         => IDLE_S);
94	
95	   signal r   : RegType := REG_INIT_C;
96	   signal rin : RegType;
97	
98	   -- attribute dont_touch      : string;
99	   -- attribute dont_touch of r : signal is "TRUE";
100	
101	begin
102	
103	   comb : process (arpAckSlaves, arpReqMasters, ibArpMaster, localIp, localMac,
104	                   obArpSlave, r, rst) is
105	      variable v : RegType;
106	   begin
107	      -- Latch the current value
108	      v := r;
109	
110	      -- Reset the flags
111	      v.ibArpSlave := AXI_STREAM_SLAVE_INIT_C;
112	      if obArpSlave.tReady = '1' then
113	         v.txArpMaster := AXI_STREAM_MASTER_INIT_C;
114	      end if;
115	      for i in CLIENT_SIZE_G-1 downto 0 loop
116	         v.arpReqSlaves(i) := AXI_STREAM_SLAVE_INIT_C;
117	         if arpAckSlaves(i).tReady = '1' then
118	            v.arpAckMasters(i) := AXI_STREAM_MASTER_INIT_C;
119	         end if;
120	      end loop;
121	
122	      -- Update the timers
123	      for i in CLIENT_SIZE_G-1 downto 0 loop
124	         if r.arpTimers(i) /= 0 then
125	            -- Decrement the timers
126	            v.arpTimers(i) := r.arpTimers(i) - 1;
127	         end if;
128	      end loop;
129	
130	      -- State Machine
131	      case r.state is
132	         ----------------------------------------------------------------------
133	         when IDLE_S =>
134	            -- Reset the counter
135	            v.cnt := 0;
136	            -- Check for inbound data
137	            if (ibArpMaster.tValid = '1') then
138	               -- Next state
139	               v.state := RX_S;
140	            else
141	               -- Increment the counter
142	               if r.reqCnt = (CLIENT_SIZE_G-1) then
143	                  v.reqCnt := 0;
144	               else
145	                  v.reqCnt := r.reqCnt + 1;
146	               end if;
147	               -- Check the tValid and timer
148	               if (arpReqMasters(r.reqCnt).tValid = '1') and (r.arpTimers(r.reqCnt) = 0) then
149	                  -- Set the timer
150	                  v.arpTimers(r.reqCnt) := TIMER_1_SEC_C;
151	                  -- Check if localhost
152	                  if localIp = arpReqMasters(r.reqCnt).tData(31 downto 0) then
153	                     -- ACK the request
154	                     v.arpReqSlaves(r.ackCnt).tReady              := '1';
155	                     v.arpAckMasters(r.ackCnt).tValid             := '1';
156	                     v.arpAckMasters(r.ackCnt).tData(47 downto 0) := localMac;
157	                  else
158	                     v.tData(0)(47 downto 0)    := BROADCAST_MAC_C;
159	                     v.tData(0)(95 downto 48)   := localMac;
160	                     v.tData(0)(111 downto 96)  := ARP_TYPE_C;
161	                     v.tData(0)(127 downto 112) := HARDWWARE_TYPE_C;
162	                     v.tData(1)(15 downto 0)    := PROTOCOL_TYPE_C;
163	                     v.tData(1)(23 downto 16)   := HARDWWARE_LEN_C;
164	                     v.tData(1)(31 downto 24)   := PROTOCOL_LEN_C;
165	                     v.tData(1)(47 downto 32)   := ARP_REQ_C;
166	                     v.tData(1)(95 downto 48)   := localMac;
167	                     v.tData(1)(127 downto 96)  := localIp;
168	                     v.tData(2)(47 downto 0)    := BROADCAST_MAC_C;
169	                     v.tData(2)(79 downto 48)   := arpReqMasters(r.reqCnt).tData(31 downto 0);  -- Known IP address
170	                     v.tData(2)(127 downto 80)  := (others => '0');
171	                     -- Next state
172	                     v.state                    := TX_S;
173	                  end if;
174	               end if;
175	            end if;
176	         ----------------------------------------------------------------------
177	         when RX_S =>
178	            -- Check for data
179	            if (ibArpMaster.tValid = '1') then
180	               -- Accept for data
181	               v.ibArpSlave.tReady := '1';
182	               -- Word[0]
183	               if r.cnt = 0 then
184	                  v.tData(0) := ibArpMaster.tData(127 downto 0);
185	                  if (ssiGetUserSof(EMAC_AXIS_CONFIG_C, ibArpMaster) = '1') then
186	                     -- Increment the counter
187	                     v.cnt := r.cnt + 1;
188	                  else
189	                     -- Next state
190	                     v.state := IDLE_S;
191	                  end if;
192	               -- Word[1]
193	               elsif r.cnt = 1 then
194	                  v.tData(1) := ibArpMaster.tData(127 downto 0);
195	                  if (ibArpMaster.tLast = '0') then
196	                     -- Increment the counter
197	                     v.cnt := r.cnt + 1;
198	                  else
199	                     -- Next state
200	                     v.state := IDLE_S;
201	                  end if;
202	               -- Word[2]
203	               elsif r.cnt = 2 then
204	                  v.tData(2) := ibArpMaster.tData(127 downto 0);
205	                  if (ibArpMaster.tLast = '0') then
206	                     -- Increment the counter
207	                     v.cnt := r.cnt + 1;
208	                  else
209	                     -- Check for EOFE error
210	                     if (ssiGetUserEofe(EMAC_AXIS_CONFIG_C, ibArpMaster) = '1') then
211	                        -- Next state
212	                        v.state := IDLE_S;
213	                     else
214	                        -- Next state
215	                        v.state := CHECK_S;
216	                     end if;
217	                  end if;
218	               -- Word[3] (or more)
219	               else
220	                  if ibArpMaster.tLast = '1' then
221	                     -- Check for EOFE error
222	                     if (ssiGetUserEofe(EMAC_AXIS_CONFIG_C, ibArpMaster) = '1') then
223	                        -- Next state
224	                        v.state := IDLE_S;
225	                     else
226	                        -- Next state
227	                        v.state := CHECK_S;
228	                     end if;
229	                  end if;
230	               end if;
231	            end if;
232	         ----------------------------------------------------------------------
233	         when CHECK_S =>
234	            -- Default next state
235	            v.state := IDLE_S;
236	            -- Reset the counter
237	            v.cnt   := 0;
238	            if (r.tData(0)(127 downto 112) = HARDWWARE_TYPE_C)  -- Check for valid Hardware type
239	               and (r.tData(1)(15 downto 0) = PROTOCOL_TYPE_C)  -- Check for valid Protocol type
240	               and (r.tData(1)(23 downto 16) = HARDWWARE_LEN_C)  -- Check for valid Hardware Length
241	               and (r.tData(1)(31 downto 24) = PROTOCOL_LEN_C) then  -- Check for valid Protocol Length
242	               -- Check OP-CODE = ARP Request
243	               if (r.tData(1)(47 downto 32) = ARP_REQ_C) then
244	                  -- Check if the target IP address matches local address
245	                  if r.tData(2)(79 downto 48) = localIp then
246	                     -- Modified the local buffer to become a reply packet
247	                     v.tData(0)(47 downto 0)   := r.tData(0)(95 downto 48);
248	                     v.tData(0)(95 downto 48)  := localMac;
249	                     v.tData(1)(47 downto 32)  := ARP_REPLY_C;
250	                     v.tData(1)(95 downto 48)  := localMac;
251	                     v.tData(1)(127 downto 96) := localIp;
252	                     v.tData(2)(47 downto 0)   := r.tData(1)(95 downto 48);
253	                     v.tData(2)(79 downto 48)  := r.tData(1)(127 downto 96);
254	                     v.tData(2)(127 downto 80) := (others => '0');
255	                     -- Next state
256	                     v.state                   := TX_S;
257	                  end if;
258	               -- Check OP-CODE = ARP Reply
259	               elsif (r.tData(1)(47 downto 32) = ARP_REPLY_C) then
260	                  -- Check if the target IP + MAC address matches local address
261	                  if (r.tData(2)(47 downto 0) = localMac) and (r.tData(2)(79 downto 48) = localIp) then
262	                     -- Next state
263	                     v.state := SCAN_S;
264	                  end if;
265	               end if;
266	            end if;
267	         ----------------------------------------------------------------------
268	         when SCAN_S =>
269	            -- Check the tValid
270	            if (arpReqMasters(r.ackCnt).tValid = '1') and (v.arpAckMasters(r.ackCnt).tValid = '0') then
271	               -- Check if Source's IP address match request IP address
272	               if arpReqMasters(r.ackCnt).tData(31 downto 0) = r.tData(1)(127 downto 96) then
273	                  -- ACK the request
274	                  v.arpReqSlaves(r.ackCnt).tReady              := '1';
275	                  v.arpAckMasters(r.ackCnt).tValid             := '1';
276	                  v.arpAckMasters(r.ackCnt).tData(47 downto 0) := r.tData(1)(95 downto 48);  -- Source's MAC address
277	                  -- Reset the timer
278	                  v.arpTimers(r.ackCnt)                        := 0;
279	               end if;
280	            end if;
281	            -- Check the counter
282	            if r.ackCnt = (CLIENT_SIZE_G-1) then
283	               -- Reset the counter
284	               v.ackCnt := 0;
285	               -- Next state
286	               v.state  := IDLE_S;
287	            else
288	               v.ackCnt := r.ackCnt + 1;
289	            end if;
290	         ----------------------------------------------------------------------
291	         when TX_S =>
292	            -- Check if ready to move data
293	            if v.txArpMaster.tValid = '0' then
294	               -- Move data
295	               v.txArpMaster.tValid              := '1';
296	               v.txArpMaster.tData(127 downto 0) := r.tData(r.cnt);
297	               -- Increment the counter
298	               v.cnt                             := r.cnt + 1;
299	               if r.cnt = 0 then
300	                  ssiSetUserSof(EMAC_AXIS_CONFIG_C, v.txArpMaster, '1');
301	               elsif r.cnt = 2 then
302	                  -- Set the EOF flag
303	                  v.txArpMaster.tLast              := '1';
304	                  -- Set the tKeep
305	                  v.txArpMaster.tKeep(15 downto 0) := x"03FF";
306	                  -- Next state
307	                  v.state                          := IDLE_S;
308	               end if;
309	            end if;
310	      ----------------------------------------------------------------------
311	      end case;
312	
313	      -- Combinatorial outputs before the reset
314	      arpReqSlaves <= v.arpReqSlaves;
315	      ibArpSlave   <= v.ibArpSlave;
316	
317	      -- Reset
318	      if (RST_ASYNC_G = false and rst = RST_POLARITY_G) then
319	         v := REG_INIT_C;
320	      end if;
321	
322	      -- Register the variable for next clock cycle
323	      rin <= v;
324	
325	      -- Registered Outputs
326	      arpAckMasters <= r.arpAckMasters;
327	      obArpMaster   <= r.txArpMaster;
328	
329	   end process comb;
330	
331	   seq : process (clk, rst) is
332	   begin
333	      if (RST_ASYNC_G and rst = RST_POLARITY_G) then
334	         r <= REG_INIT_C after TPD_G;
335	      elsif rising_edge(clk) then
336	         r <= rin after TPD_G;
337	      end if;
338	   end process seq;
339	
340	end rtl;
341

