13	-------------------------------------------------------------------------------
14	
15	library ieee;
16	use ieee.std_logic_1164.all;
17	use ieee.std_logic_unsigned.all;
18	use ieee.std_logic_arith.all;
19	
20	library surf;
21	use surf.StdRtlPkg.all;
22	use surf.AxiStreamPkg.all;
23	use surf.SsiPkg.all;
24	use surf.EthMacPkg.all;
25	
26	entity IcmpEngine is
27	   generic (
28	      TPD_G          : time    := 1 ns;
29	      RST_POLARITY_G : sl      := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
30	      RST_ASYNC_G    : boolean := false);
31	   port (
32	      -- Local Configurations
33	      localIp      : in  slv(31 downto 0);  --  big-Endian configuration
34	      -- Interface to ICMP Engine
35	      ibIcmpMaster : in  AxiStreamMasterType;
36	      ibIcmpSlave  : out AxiStreamSlaveType;
37	      obIcmpMaster : out AxiStreamMasterType;
38	      obIcmpSlave  : in  AxiStreamSlaveType;
39	      -- Clock and Reset
40	      clk          : in  sl;
41	      rst          : in  sl);
42	end IcmpEngine;
43	
44	architecture rtl of IcmpEngine is
45	
46	   type StateType is (
47	      IDLE_S,
48	      RX_HDR_S,
49	      TX_HDR_S,
50	      MOVE_S);
51	
52	   type RegType is record
53	      tData        : slv(127 downto 0);
54	      checksum     : slv(15 downto 0);
55	      ibIcmpSlave  : AxiStreamSlaveType;
56	      obIcmpMaster : AxiStreamMasterType;
57	      state        : StateType;
58	   end record RegType;
59	   constant REG_INIT_C : RegType := (
60	      tData        => (others => '0'),
61	      checksum     => (others => '0'),
62	      ibIcmpSlave  => AXI_STREAM_SLAVE_INIT_C,
63	      obIcmpMaster => AXI_STREAM_MASTER_INIT_C,
64	      state        => IDLE_S);
65	
66	   signal r   : RegType := REG_INIT_C;
67	   signal rin : RegType;
68	
69	   -- attribute dont_touch      : string;
70	   -- attribute dont_touch of r : signal is "TRUE";
71	
72	begin
73	
74	   comb : process (ibIcmpMaster, localIp, obIcmpSlave, r, rst) is
75	      variable v    : RegType;
76	      variable eofe : sl;
77	   begin
78	      -- Latch the current value
79	      v := r;
80	
81	      -- Reset the flags
82	      v.ibIcmpSlave := AXI_STREAM_SLAVE_INIT_C;
83	      if obIcmpSlave.tReady = '1' then
84	         v.obIcmpMaster.tValid := '0';
85	         v.obIcmpMaster.tLast  := '0';
86	         v.obIcmpMaster.tUser  := (others => '0');
87	         v.obIcmpMaster.tKeep  := (others => '1');
88	      end if;
89	
90	      -- Update the variable
91	      eofe := ssiGetUserEofe(EMAC_AXIS_CONFIG_C, ibIcmpMaster);
92	
93	      ------------------------------------------------
94	      -- Notes: Non-Standard IPv4 Pseudo Header Format
95	      ------------------------------------------------
96	      -- tData[0][47:0]   = Remote MAC Address
97	      -- tData[0][63:48]  = zeros
98	      -- tData[0][95:64]  = Remote IP Address
99	      -- tData[0][127:96] = Local IP address
100	      -- tData[1][7:0]    = zeros
101	      -- tData[1][15:8]   = Protocol Type = ICMP
102	      -- tData[1][31:16]  = IPv4 Pseudo header length
103	      -- tData[1][39:32]  = Type of message
104	      -- tData[1][47:40]  = Code
105	      -- tData[1][63:48]  = Checksum
106	      -- tData[1][95:64]  = ICMP Header
107	      -- tData[1][127:96] = ICMP Datagram
108	      ------------------------------------------------
109	
110	      -- State Machine
111	      case r.state is
112	         ----------------------------------------------------------------------
113	         when IDLE_S =>
114	            -- Check for data
115	            if (ibIcmpMaster.tValid = '1') then
116	               -- Accept the data
117	               v.ibIcmpSlave.tReady := '1';
118	               -- Check for SOF with no EOF
119	               if (ssiGetUserSof(EMAC_AXIS_CONFIG_C, ibIcmpMaster) = '1') and (ibIcmpMaster.tLast = '0') then
120	                  -- Copy IPv4 base header
121	                  v.tData(63 downto 0)   := ibIcmpMaster.tData(63 downto 0);
122	                  -- Swap the IP addresses
123	                  v.tData(95 downto 64)  := ibIcmpMaster.tData(127 downto 96);  -- SRC IP
124	                  v.tData(127 downto 96) := ibIcmpMaster.tData(95 downto 64);  -- DST IP
125	                  if ibIcmpMaster.tData(127 downto 96) = localIp then
126	                     -- Next state
127	                     v.state := RX_HDR_S;
128	                  end if;
129	               end if;
130	            end if;
131	         ----------------------------------------------------------------------
132	         when RX_HDR_S =>
133	            -- Check for data
134	            if (ibIcmpMaster.tValid = '1') and (v.obIcmpMaster.tValid = '0') then
135	               -- Check for Echo request
136	               if (ibIcmpMaster.tData(47 downto 32) = x"0008") then
137	                  -- Map the inbound checksum to little Endian
138	                  v.checksum(15 downto 8) := ibIcmpMaster.tData(55 downto 48);
139	                  v.checksum(7 downto 0)  := ibIcmpMaster.tData(63 downto 56);
140	                  -- Check if roll over case
141	                  if (v.checksum >= x"F800") then
142	                     -- Update the checksum for outbound data packet
143	                     v.checksum := v.checksum + x"0801";
144	                  else
145	                     -- Update the checksum for outbound data packet
146	                     v.checksum := v.checksum + x"0800";
147	                  end if;
148	                  ---------------------------------------------------------
149	                  -- Note: To save FPGA resources, we do NOT cache the data
150	                  --       for properly calculating the checksum.  Instead,
151	                  --       we calculate the outbound checksum with respect
152	                  --       to the inbound checksum and assume that the
153	                  --       computer interface will probably check our
154	                  --       outbound packet.
155	                  ---------------------------------------------------------
156	                  -- Send the IPv4 base header
157	                  v.obIcmpMaster.tValid              := '1';
158	                  v.obIcmpMaster.tData(127 downto 0) := r.tData;
159	                  ssiSetUserSof(EMAC_AXIS_CONFIG_C, v.obIcmpMaster, '1');
160	                  -- Next state
161	                  v.state                            := TX_HDR_S;
162	               else
163	                  -- Next state
164	                  v.state := IDLE_S;
165	               end if;
166	            end if;
167	         ----------------------------------------------------------------------
168	         when TX_HDR_S =>
169	            -- Check for data
170	            if (ibIcmpMaster.tValid = '1') and (v.obIcmpMaster.tValid = '0') then
171	               -- Accept the data
172	               v.ibIcmpSlave.tReady                := '1';
173	               -- Send the IPv4 base header
174	               v.obIcmpMaster.tValid               := '1';
175	               v.obIcmpMaster.tData(31 downto 0)   := ibIcmpMaster.tData(31 downto 0);
176	               v.obIcmpMaster.tData(47 downto 32)  := x"0000";  -- Echo reply
177	               v.obIcmpMaster.tData(55 downto 48)  := r.checksum(15 downto 8);
178	               v.obIcmpMaster.tData(63 downto 56)  := r.checksum(7 downto 0);
179	               v.obIcmpMaster.tData(127 downto 64) := ibIcmpMaster.tData(127 downto 64);
180	               v.obIcmpMaster.tKeep                := ibIcmpMaster.tKeep;
181	               v.obIcmpMaster.tLast                := ibIcmpMaster.tLast;
182	               if ibIcmpMaster.tLast = '1' then
183	                  -- Echo back EOFE
184	                  ssiSetUserEofe(EMAC_AXIS_CONFIG_C, v.obIcmpMaster, eofe);
185	                  -- Next state
186	                  v.state := IDLE_S;
187	               else
188	                  -- Next state
189	                  v.state := MOVE_S;
190	               end if;
191	            end if;
192	         ----------------------------------------------------------------------
193	         when MOVE_S =>
194	            -- Check for data
195	            if (ibIcmpMaster.tValid = '1') and (v.obIcmpMaster.tValid = '0') then
196	               -- Accept the data
197	               v.ibIcmpSlave.tReady  := '1';
198	               -- Send the IPv4 base header
199	               v.obIcmpMaster.tValid := '1';
200	               v.obIcmpMaster.tData  := ibIcmpMaster.tData;
201	               v.obIcmpMaster.tKeep  := ibIcmpMaster.tKeep;
202	               v.obIcmpMaster.tLast  := ibIcmpMaster.tLast;
203	               if ibIcmpMaster.tLast = '1' then
204	                  -- Echo back EOFE
205	                  ssiSetUserEofe(EMAC_AXIS_CONFIG_C, v.obIcmpMaster, eofe);
206	                  -- Next state
207	                  v.state := IDLE_S;
208	               end if;
209	            end if;
210	      ----------------------------------------------------------------------
211	      end case;
212	
213	      -- Combinatorial outputs before the reset
214	      ibIcmpSlave <= v.ibIcmpSlave;
215	
216	      -- Reset
217	      if (RST_ASYNC_G = false and rst = RST_POLARITY_G) then
218	         v := REG_INIT_C;
219	      end if;
220	
221	      -- Register the variable for next clock cycle
222	      rin <= v;
223	
224	      -- Registered Outputs
225	      obIcmpMaster <= r.obIcmpMaster;
226	
227	   end process comb;
228	
229	   seq : process (clk, rst) is
230	   begin
231	      if (RST_ASYNC_G and rst = RST_POLARITY_G) then
232	         r <= REG_INIT_C after TPD_G;
233	      elsif rising_edge(clk) then
234	         r <= rin after TPD_G;
235	      end if;
236	   end process seq;
237	
238	end rtl;
