1	-------------------------------------------------------------------------------
2	-- Company    : SLAC National Accelerator Laboratory
3	-------------------------------------------------------------------------------
4	-- Description: Igmp Engine (A.K.A. "ping" protocol)
5	-------------------------------------------------------------------------------
6	-- TODO: Add Leave Group messaging (Message Type = 0x17) support
7	-------------------------------------------------------------------------------
8	-- This file is part of 'SLAC Firmware Standard Library'.
9	-- It is subject to the license terms in the LICENSE.txt file found in the
10	-- top-level directory of this distribution and at:
11	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
12	-- No part of 'SLAC Firmware Standard Library', including this file,
13	-- may be copied, modified, propagated, or distributed except according to
14	-- the terms contained in the LICENSE.txt file.
15	-------------------------------------------------------------------------------
16	
17	library ieee;
18	use ieee.std_logic_1164.all;
19	use ieee.std_logic_unsigned.all;
20	use ieee.std_logic_arith.all;
21	
22	library surf;
23	use surf.StdRtlPkg.all;
24	use surf.AxiStreamPkg.all;
25	use surf.SsiPkg.all;
26	use surf.EthMacPkg.all;
27	
28	entity IgmpV2Engine is
29	   generic (
30	      TPD_G          : time     := 1 ns;
31	      RST_POLARITY_G : sl       := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
32	      RST_ASYNC_G    : boolean  := false;
33	      IGMP_GRP_SIZE  : positive := 1;
34	      CLK_FREQ_G     : real     := 156.25E+06);  -- In units of Hz
35	   port (
36	      -- Local Configurations
37	      localIp      : in  slv(31 downto 0);       --  big-Endian configuration
38	      igmpIp       : in  Slv32Array(IGMP_GRP_SIZE-1 downto 0);  --  big-Endian configuration
39	      -- Interface to Igmp Engine
40	      ibIgmpMaster : in  AxiStreamMasterType;
41	      ibIgmpSlave  : out AxiStreamSlaveType;
42	      obIgmpMaster : out AxiStreamMasterType;
43	      obIgmpSlave  : in  AxiStreamSlaveType;
44	      -- Clock and Reset
45	      clk          : in  sl;
46	      rst          : in  sl);
47	end IgmpV2Engine;
48	
49	architecture rtl of IgmpV2Engine is
50	
51	   constant TIMER_100MS_C : natural := getTimeRatio(CLK_FREQ_G, 10.0);  -- units of 0.1 second
52	
53	   type RxStateType is (
54	      RX_IDLE_S,
55	      RX_MSG_S);
56	
57	   type TxStateType is (
58	      TX_IDLE_S,
59	      TX_MSG_S);
60	
61	   type RegType is record
62	      txCnt        : natural range 0 to IGMP_GRP_SIZE-1;
63	      cnt          : natural range 0 to TIMER_100MS_C;
64	      sendReport   : slv(IGMP_GRP_SIZE-1 downto 0);
65	      rndCnt       : slv(7 downto 0);
66	      timer        : slv(7 downto 0);
67	      obIgmpMaster : AxiStreamMasterType;
68	      rxState      : RxStateType;
69	      txState      : TxStateType;
70	   end record RegType;
71	   constant REG_INIT_C : RegType := (
72	      txCnt        => 0,
73	      cnt          => 0,
74	      sendReport   => (others => '1'),  -- Send report message at power up
75	      rndCnt       => (others => '0'),
76	      timer        => (others => '1'),  -- Power up delay before sending report messages
77	      obIgmpMaster => AXI_STREAM_MASTER_INIT_C,
78	      rxState      => RX_IDLE_S,
79	      txState      => TX_IDLE_S);
80	
81	   signal r   : RegType := REG_INIT_C;
82	   signal rin : RegType;
83	
84	   -- attribute dont_touch      : string;
85	   -- attribute dont_touch of r : signal is "TRUE";
86	
87	begin
88	
89	   comb : process (ibIgmpMaster, igmpIp, localIp, obIgmpSlave, r, rst) is
90	      variable v      : RegType;
91	      variable rxXsum : slv(17 downto 0);
92	      variable txXsum : slv(17 downto 0);
93	   begin
94	      -- Latch the current value
95	      v := r;
96	
97	      ------------------------------------------------
98	      -- Notes: Non-Standard IPv4 Pseudo Header Format
99	      ------------------------------------------------
100	      -- tData[0][47:0]   = Remote MAC Address
101	      -- tData[0][63:48]  = zeros
102	      -- tData[0][95:64]  = Remote IP Address
103	      -- tData[0][127:96] = Local IP address
104	      -- tData[1][7:0]    = zeros
105	      -- tData[1][15:8]   = Protocol Type = Igmp
106	      -- tData[1][31:16]  = IPv4 Pseudo header length
107	      -- tData[1][39:32]  = Type of message
108	      -- tData[1][47:40]  = Max Resp Time
109	      -- tData[1][63:48]  = Checksum
110	      -- tData[1][95:64]  = Group Address
111	      ------------------------------------------------
112	
113	      -- Calculate the RX checksum
114	      rxXsum := resize(ibIgmpMaster.tData(39 downto 32) & ibIgmpMaster.tData(47 downto 40), 18);
115	      rxXsum := resize(ibIgmpMaster.tData(71 downto 64) & ibIgmpMaster.tData(79 downto 72), 18) + rxXsum;
116	      rxXsum := resize(ibIgmpMaster.tData(87 downto 80) & ibIgmpMaster.tData(95 downto 88), 18) + rxXsum;
117	      rxXsum := resize(rxXsum(17 downto 16), 18) + resize(rxXsum(15 downto 0), 18);
118	      rxXsum := not(rxXsum);
119	
120	      -- Increment the "random" timer
121	      v.rndCnt := r.rndCnt + 1;
122	
123	      -- RX State Machine
124	      case r.rxState is
125	         ----------------------------------------------------------------------
126	         when RX_IDLE_S =>
127	            -- Check for data with SOF and no EOF
128	            if (ibIgmpMaster.tValid = '1') and (ssiGetUserSof(EMAC_AXIS_CONFIG_C, ibIgmpMaster) = '1') and (ibIgmpMaster.tLast = '0') then
129	               -- Next state
130	               v.rxState := RX_MSG_S;
131	            end if;
132	         ----------------------------------------------------------------------
133	         when RX_MSG_S =>
134	            -- Check for data
135	            if (ibIgmpMaster.tValid = '1') then
136	
137	               -- Next state
138	               v.rxState := RX_IDLE_S;
139	
140	               -- Check for valid checksum
141	               if (rxXsum(15 downto 8) = ibIgmpMaster.tData(55 downto 48)) and (rxXsum(7 downto 0) = ibIgmpMaster.tData(63 downto 56)) then
142	
143	                  -- Check for Membership Query message
144	                  if (ibIgmpMaster.tData(39 downto 32) = x"11") and (ibIgmpMaster.tData(95 downto 64) = 0) then
145	                     -- Loop through the group addresses
146	                     for i in IGMP_GRP_SIZE-1 downto 0 loop
147	                        -- Check if matches group address
148	                        if (igmpIp(i) /= 0) then
149	                           -- Reset the flag
150	                           v.sendReport(i) := '1';
151	                        end if;
152	                        -- Set the "random" timer
153	                        v.timer := ibIgmpMaster.tData(47 downto 40);
154	                        if resize(r.rndCnt(7 downto i), 8) < ibIgmpMaster.tData(47 downto 40) then
155	                           v.timer := resize(r.rndCnt(7 downto i), 8);
156	                        end if;
157	                     end loop;
158	                  end if;
159	
160	                  -- Check for Membership Report message
161	                  if (ibIgmpMaster.tData(39 downto 32) = x"16") then
162	                     -- Loop through the group addresses
163	                     for i in IGMP_GRP_SIZE-1 downto 0 loop
164	                        -- Check if matches group address
165	                        if (igmpIp(i) = ibIgmpMaster.tData(95 downto 64)) then
166	                           -- Reset the flag
167	                           v.sendReport(i) := '0';
168	                        end if;
169	                     end loop;
170	                  end if;
171	
172	               end if;
173	            end if;
174	      ----------------------------------------------------------------------
175	      end case;
176	
177	      -- Check for timeout
178	      if (r.cnt = (TIMER_100MS_C-1)) then
179	         -- Reset the counter
180	         v.cnt := 0;
181	         -- Check if need to decrement timer
182	         if (r.timer /= 0) then
183	            v.timer := r.timer - 1;
184	         end if;
185	      else
186	         -- Increment the timer
187	         v.cnt := r.cnt + 1;
188	      end if;
189	
190	      -- Reset the flags
191	      if obIgmpSlave.tReady = '1' then
192	         v.obIgmpMaster.tValid := '0';
193	         v.obIgmpMaster.tLast  := '0';
194	         v.obIgmpMaster.tUser  := (others => '0');
195	         v.obIgmpMaster.tKeep  := (others => '1');
196	      end if;
197	
198	      -- Calculate the TX checksum
199	      txXsum := resize(x"16" & x"00", 18);
200	      txXsum := resize(r.obIgmpMaster.tData(103 downto 96) & r.obIgmpMaster.tData(111 downto 104), 18) + txXsum;
201	      txXsum := resize(r.obIgmpMaster.tData(119 downto 112) & r.obIgmpMaster.tData(127 downto 120), 18) + txXsum;
202	      txXsum := resize(txXsum(17 downto 16), 18) + resize(txXsum(15 downto 0), 18);
203	      txXsum := not(txXsum);
204	
205	      -- TX State Machine
206	      case r.txState is
207	         ----------------------------------------------------------------------
208	         when TX_IDLE_S =>
209	            -- Check for timeout
210	            if (r.timer = 0) then
211	
212	               -- Check if ready to move data
213	               if (v.obIgmpMaster.tValid = '0') then
214	
215	                  -- Setup the IPv4 base header
216	                  ssiSetUserSof(EMAC_AXIS_CONFIG_C, v.obIgmpMaster, '1');
217	                  v.obIgmpMaster.tData(47 downto 0)   := igmpIp(r.txCnt)(31 downto 8) & x"5E_00_01";  -- IPv4mcast
218	                  v.obIgmpMaster.tData(95 downto 64)  := localIp;  -- SRC IP
219	                  v.obIgmpMaster.tData(127 downto 96) := igmpIp(r.txCnt);  -- DST IP
220	
221	                  -- Check if need to send report and non-zero group IP
222	                  if (r.sendReport(r.txCnt) = '1') and (igmpIp(r.txCnt) /= 0) then
223	
224	                     -- Clear the flag
225	                     v.sendReport(r.txCnt) := '0';
226	
227	                     -- Send the IPv4 base header
228	                     v.obIgmpMaster.tValid := '1';
229	
230	                     -- Next state
231	                     v.txState := TX_MSG_S;
232	
233	                  end if;
234	
235	                  -- Increment counter
236	                  if (r.txCnt = IGMP_GRP_SIZE-1) then
237	                     v.txCnt := 0;
238	                  else
239	                     v.txCnt := r.txCnt + 1;
240	                  end if;
241	
242	               end if;
243	            end if;
244	         ----------------------------------------------------------------------
245	         when TX_MSG_S =>
246	            -- Check if ready to move data
247	            if (v.obIgmpMaster.tValid = '0') then
248	
249	               -- Next state
250	               v.txState := TX_IDLE_S;
251	
252	               -- Send the Membership Report message
253	               v.obIgmpMaster.tValid              := '1';
254	               v.obIgmpMaster.tLast               := '1';
255	               v.obIgmpMaster.tKeep               := resize(x"FFF", AXI_STREAM_MAX_TKEEP_WIDTH_C);  -- 96-bit word
256	               v.obIgmpMaster.tData(39 downto 32) := x"16";  -- IGMPv2 Membership Report
257	               v.obIgmpMaster.tData(47 downto 40) := x"00";  -- Max Resp Time
258	               v.obIgmpMaster.tData(55 downto 48) := txXsum(15 downto 8);  -- Checksum[15:8]
259	               v.obIgmpMaster.tData(63 downto 56) := txXsum(7 downto 0);  -- Checksum[7:0]
260	               v.obIgmpMaster.tData(95 downto 64) := r.obIgmpMaster.tData(127 downto 96);  -- DST IP = Group Address
261	
262	            end if;
263	      ----------------------------------------------------------------------
264	      end case;
265	
266	      -- Outputs
267	      ibIgmpSlave  <= AXI_STREAM_SLAVE_FORCE_C;
268	      obIgmpMaster <= r.obIgmpMaster;
269	
270	      -- Reset
271	      if (RST_ASYNC_G = false and rst = RST_POLARITY_G) then
272	         v := REG_INIT_C;
273	      end if;
274	
275	      -- Register the variable for next clock cycle
276	      rin <= v;
277	
278	   end process comb;
279	
280	   seq : process (clk, rst) is
281	   begin
282	      if (RST_ASYNC_G and rst = RST_POLARITY_G) then
283	         r <= REG_INIT_C after TPD_G;
284	      elsif rising_edge(clk) then
285	         r <= rin after TPD_G;
286	      end if;
287	   end process seq;
288	
289	end rtl;
