1	-------------------------------------------------------------------------------
2	-- Company    : SLAC National Accelerator Laboratory
3	-------------------------------------------------------------------------------
4	-- Description: IPv4 TX Engine Module
5	-- Note: IPv4 checksum checked in EthMac core
6	-------------------------------------------------------------------------------
7	-- This file is part of 'SLAC Firmware Standard Library'.
8	-- It is subject to the license terms in the LICENSE.txt file found in the
9	-- top-level directory of this distribution and at:
10	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
11	-- No part of 'SLAC Firmware Standard Library', including this file,
12	-- may be copied, modified, propagated, or distributed except according to
13	-- the terms contained in the LICENSE.txt file.
14	-------------------------------------------------------------------------------
15	
16	library ieee;
17	use ieee.std_logic_1164.all;
18	use ieee.std_logic_unsigned.all;
19	use ieee.std_logic_arith.all;
20	
21	library surf;
22	use surf.StdRtlPkg.all;
23	use surf.AxiStreamPkg.all;
24	use surf.SsiPkg.all;
25	use surf.EthMacPkg.all;
26	
27	entity IpV4EngineTx is
28	   generic (
29	      TPD_G           : time            := 1 ns;
30	      RST_POLARITY_G  : sl              := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
31	      RST_ASYNC_G     : boolean         := false;
32	      PROTOCOL_SIZE_G : positive        := 1;
33	      PROTOCOL_G      : Slv8Array       := (0 => UDP_C);
34	      TTL_G           : slv(7 downto 0) := x"20");
35	   port (
36	      -- Local Configurations
37	      localMac          : in  slv(47 downto 0);  --  big-Endian configuration
38	      -- Interface to Ethernet Frame MUX/DEMUX
39	      obIpv4Master      : out AxiStreamMasterType;
40	      obIpv4Slave       : in  AxiStreamSlaveType;
41	      localhostMaster   : out AxiStreamMasterType;
42	      localhostSlave    : in  AxiStreamSlaveType;
43	      -- Interface to Protocol Engine
44	      obProtocolMasters : in  AxiStreamMasterArray(PROTOCOL_SIZE_G-1 downto 0);
45	      obProtocolSlaves  : out AxiStreamSlaveArray(PROTOCOL_SIZE_G-1 downto 0);
46	      -- Clock and Reset
47	      clk               : in  sl;
48	      rst               : in  sl);
49	end IpV4EngineTx;
50	
51	architecture rtl of IpV4EngineTx is
52	
53	   type StateType is (
54	      IDLE_S,
55	      IPV4_HDR0_S,
56	      IPV4_HDR1_S,
57	      IPV4_HDR2_S,
58	      MOVE_S,
59	      LAST_S);
60	
61	   type RegType is record
62	      eofe     : sl;
63	      tKeep    : slv(15 downto 0);
64	      tData    : slv(127 downto 0);
65	      tDest    : slv(7 downto 0);
66	      id       : slv(15 downto 0);
67	      rxSlave  : AxiStreamSlaveType;
68	      txMaster : AxiStreamMasterType;
69	      state    : StateType;
70	   end record RegType;
71	   constant REG_INIT_C : RegType := (
72	      eofe     => '0',
73	      tKeep    => (others => '0'),
74	      tData    => (others => '0'),
75	      tDest    => (others => '0'),
76	      id       => (others => '0'),
77	      rxSlave  => AXI_STREAM_SLAVE_INIT_C,
78	      txMaster => AXI_STREAM_MASTER_INIT_C,
79	      state    => IDLE_S);
80	
81	   signal r   : RegType := REG_INIT_C;
82	   signal rin : RegType;
83	
84	   signal rxMaster : AxiStreamMasterType;
85	   signal rxSlave  : AxiStreamSlaveType;
86	
87	   signal txMaster : AxiStreamMasterType;
88	   signal txSlave  : AxiStreamSlaveType;
89	
90	   signal mAxisMaster : AxiStreamMasterType;
91	   signal mAxisSlave  : AxiStreamSlaveType;
92	
93	   -- attribute dont_touch              : string;
94	   -- attribute dont_touch of r         : signal is "TRUE";
95	
96	begin
97	
98	   AxiStreamMux_Inst : entity surf.AxiStreamMux
99	      generic map (
100	         TPD_G          => TPD_G,
101	         RST_POLARITY_G => RST_POLARITY_G,
102	         RST_ASYNC_G    => RST_ASYNC_G,
103	         PIPE_STAGES_G  => 0,
104	         NUM_SLAVES_G   => PROTOCOL_SIZE_G)
105	      port map (
106	         -- Clock and reset
107	         axisClk      => clk,
108	         axisRst      => rst,
109	         -- Slave
110	         sAxisMasters => obProtocolMasters,
111	         sAxisSlaves  => obProtocolSlaves,
112	         -- Masters
113	         mAxisMaster  => rxMaster,
114	         mAxisSlave   => rxSlave);
115	
116	   comb : process (localMac, r, rst, rxMaster, txSlave) is
117	      variable v : RegType;
118	      variable i : natural;
119	   begin
120	      -- Latch the current value
121	      v := r;
122	
123	      -- Reset the flags
124	      v.rxSlave := AXI_STREAM_SLAVE_INIT_C;
125	      if txSlave.tReady = '1' then
126	         v.txMaster.tValid := '0';
127	         v.txMaster.tLast  := '0';
128	         v.txMaster.tUser  := (others => '0');
129	         v.txMaster.tKeep  := (others => '1');
130	      end if;
131	
132	      -- State Machine
133	      case r.state is
134	         ----------------------------------------------------------------------
135	         when IDLE_S =>
136	            -- Check if ready to move data
137	            if (rxMaster.tValid = '1') and (v.txMaster.tValid = '0') then
138	               -- Accept the data
139	               v.rxSlave.tReady := '1';
140	               -- Latch the TDEST
141	               v.tDest          := rxMaster.tDest;
142	               -- Check for SOF with no EOF
143	               if (ssiGetUserSof(EMAC_AXIS_CONFIG_C, rxMaster) = '1') and (rxMaster.tLast = '0') then
144	                  -- Send the RAW Ethernet header
145	                  v.txMaster.tValid := '1';
146	                  -- Set the SOF bit
147	                  ssiSetUserSof(EMAC_AXIS_CONFIG_C, v.txMaster, '1');
148	                  -- Setup the tDest routing
149	                  if (localMac = rxMaster.tData(47 downto 0)) then
150	                     -- Local Host Path
151	                     v.txMaster.tDest := x"01";
152	                  else
153	                     -- Remote Host Path
154	                     v.txMaster.tDest := x"00";
155	                  end if;
156	                  -- Set the DST MAC and SRC MAC
157	                  v.txMaster.tData(47 downto 0)    := rxMaster.tData(47 downto 0);
158	                  v.txMaster.tData(95 downto 48)   := localMac;
159	                  v.txMaster.tData(111 downto 96)  := IPV4_TYPE_C;
160	                  v.txMaster.tData(119 downto 112) := x"45";  -- IPVersion = 4,Header length = 5
161	                  v.txMaster.tData(127 downto 120) := x"00";  --- DSCP and ECN
162	                  -- Track the leftovers
163	                  v.tData(63 downto 0)             := rxMaster.tData(127 downto 64);
164	                  -- Next state
165	                  v.state                          := IPV4_HDR0_S;
166	               end if;
167	            end if;
168	         ----------------------------------------------------------------------
169	         when IPV4_HDR0_S =>
170	            -- Check for data
171	            if (v.txMaster.tValid = '0') then
172	               -- Send the IPV4 header
173	               v.txMaster.tValid                := '1';
174	               v.txMaster.tData(7 downto 0)     := x"00";  -- IPV4_Length(15 downto 8) Note: Calculated in EthMac core
175	               v.txMaster.tData(15 downto 8)    := x"00";  -- IPV4_Length(7 downto 0)  Note: Calculated in EthMac core
176	               v.txMaster.tData(23 downto 16)   := r.id(15 downto 8);  -- IPV4_ID(15 downto 8)
177	               v.txMaster.tData(31 downto 24)   := r.id(7 downto 0);  -- IPV4_ID(7 downto 0)
178	               v.txMaster.tData(39 downto 32)   := x"40";  -- Flags(2 downto 0) =  Don't Fragment (DF) and Fragment_Offsets(12 downto 8) = 0x0
179	               v.txMaster.tData(47 downto 40)   := x"00";  -- Fragment_Offsets(7 downto 0) = 0x0
180	               v.txMaster.tData(55 downto 48)   := TTL_G;  -- Time-To-Live (number of hops before packet is discarded)
181	               v.txMaster.tData(63 downto 56)   := PROTOCOL_G(conv_integer(r.tDest));  -- Protocol
182	               v.txMaster.tData(71 downto 64)   := x"00";  -- IPV4_Checksum(15 downto 8)  Note: Filled in next state
183	               v.txMaster.tData(79 downto 72)   := x"00";  -- IPV4_Checksum(7 downto 0)   Note: Filled in next state
184	               v.txMaster.tData(111 downto 80)  := r.tData(31 downto 0);  -- Source IP Address(31 downto 0)
185	               v.txMaster.tData(127 downto 112) := r.tData(47 downto 32);  -- Destination IP Address(31 downto 16)
186	               -- Increment the counter
187	               v.id                             := r.id + 1;
188	               -- Next state
189	               v.state                          := IPV4_HDR1_S;
190	            end if;
191	         ----------------------------------------------------------------------
192	         when IPV4_HDR1_S =>
193	            -- Check if ready to move data
194	            if (rxMaster.tValid = '1') and (v.txMaster.tValid = '0') then
195	               -- Accept the data
196	               v.rxSlave.tReady                := '1';
197	               -- Update the tData bus
198	               v.txMaster.tData(15 downto 0)   := r.tData(63 downto 48);  -- Destination IP Address(15 downto 0)
199	               v.txMaster.tData(111 downto 16) := rxMaster.tData(127 downto 32);
200	               -- Update the tKeep bus
201	               v.txMaster.tKeep(1 downto 0)    := (others => '1');
202	               v.txMaster.tKeep(13 downto 2)   := rxMaster.tKeep(15 downto 4);
203	               v.txMaster.tKeep(15 downto 14)  := (others => '0');
204	               -- Get the EOFE
205	               v.eofe                          := ssiGetUserEofe(EMAC_AXIS_CONFIG_C, rxMaster);
206	               -- Check for tLast
207	               if (rxMaster.tLast = '1') then
208	                  -- Move the data
209	                  v.txMaster.tValid := '1';
210	                  -- Set the tLast flag
211	                  v.txMaster.tLast  := '1';
212	                  -- Set the EOFE
213	                  ssiSetUserEofe(EMAC_AXIS_CONFIG_C, v.txMaster, v.eofe);
214	                  -- Next state
215	                  v.state           := IDLE_S;
216	               else
217	                  -- Next state
218	                  v.state := IPV4_HDR2_S;
219	               end if;
220	            end if;
221	         ----------------------------------------------------------------------
222	         when IPV4_HDR2_S =>
223	            -- Check for data
224	            if (rxMaster.tValid = '1') and (v.txMaster.tValid = '0') then
225	               -- Accept the data
226	               v.rxSlave.tReady                 := '1';
227	               -- Move the data
228	               v.txMaster.tValid                := '1';
229	               v.txMaster.tData(127 downto 112) := rxMaster.tData(15 downto 0);
230	               v.txMaster.tKeep(13 downto 0)    := (others => '1');
231	               v.txMaster.tKeep(15 downto 14)   := rxMaster.tKeep(1 downto 0);
232	               -- Track the leftovers
233	               v.tData(111 downto 0)            := rxMaster.tData(127 downto 16);
234	               v.tKeep(13 downto 0)             := rxMaster.tKeep(15 downto 2);
235	               -- Get the EOFE
236	               v.eofe                           := ssiGetUserEofe(EMAC_AXIS_CONFIG_C, rxMaster);
237	               -- Check for tLast
238	               if (rxMaster.tLast = '1') then
239	                  -- Check the leftover tKeep is not empty
240	                  if (v.tKeep /= 0) then
241	                     -- Next state
242	                     v.state := LAST_S;
243	                  else
244	                     -- Set the EOF/EOFE
245	                     v.txMaster.tLast := '1';
246	                     ssiSetUserEofe(EMAC_AXIS_CONFIG_C, v.txMaster, v.eofe);
247	                     -- Next state
248	                     v.state          := IDLE_S;
249	                  end if;
250	               else
251	                  -- Next state
252	                  v.state := MOVE_S;
253	               end if;
254	            end if;
255	         ----------------------------------------------------------------------
256	         when MOVE_S =>
257	            -- Check for data
258	            if (rxMaster.tValid = '1') and (v.txMaster.tValid = '0') then
259	               -- Accept the data
260	               v.rxSlave.tReady                 := '1';
261	               -- Move the data
262	               v.txMaster.tValid                := '1';
263	               -- Move the data
264	               v.txMaster.tData(111 downto 0)   := r.tData(111 downto 0);
265	               v.txMaster.tData(127 downto 112) := rxMaster.tData(15 downto 0);
266	               v.txMaster.tKeep(13 downto 0)    := r.tKeep(13 downto 0);
267	               v.txMaster.tKeep(15 downto 14)   := rxMaster.tKeep(1 downto 0);
268	               -- Track the leftovers
269	               v.tData(111 downto 0)            := rxMaster.tData(127 downto 16);
270	               v.tKeep(13 downto 0)             := rxMaster.tKeep(15 downto 2);
271	               -- Get the EOFE
272	               v.eofe                           := ssiGetUserEofe(EMAC_AXIS_CONFIG_C, rxMaster);
273	               -- Check for tLast
274	               if (rxMaster.tLast = '1') then
275	                  -- Check the leftover tKeep is not empty
276	                  if (v.tKeep /= 0) then
277	                     -- Next state
278	                     v.state := LAST_S;
279	                  else
280	                     -- Set the EOF/EOFE
281	                     v.txMaster.tLast := '1';
282	                     ssiSetUserEofe(EMAC_AXIS_CONFIG_C, v.txMaster, v.eofe);
283	                     -- Next state
284	                     v.state          := IDLE_S;
285	                  end if;
286	               end if;
287	            end if;
288	         ----------------------------------------------------------------------
289	         when LAST_S =>
290	            -- Check for data
291	            if (v.txMaster.tValid = '0') then
292	               -- Move the data
293	               v.txMaster.tValid              := '1';
294	               v.txMaster.tData(127 downto 0) := r.tData;
295	               v.txMaster.tKeep(15 downto 0)  := r.tKeep;
296	               v.txMaster.tLast               := '1';
297	               ssiSetUserEofe(EMAC_AXIS_CONFIG_C, v.txMaster, r.eofe);
298	               -- Next state
299	               v.state                        := IDLE_S;
300	            end if;
301	      ----------------------------------------------------------------------
302	      end case;
303	
304	      -- Combinatorial outputs before the reset
305	      rxSlave <= v.rxSlave;
306	
307	      -- Reset
308	      if (RST_ASYNC_G = false and rst = RST_POLARITY_G) then
309	         v := REG_INIT_C;
310	      end if;
311	
312	      -- Register the variable for next clock cycle
313	      rin <= v;
314	
315	      -- Registered Outputs
316	      txMaster <= r.txMaster;
317	
318	   end process comb;
319	
320	   seq : process (clk, rst) is
321	   begin
322	      if (RST_ASYNC_G and rst = RST_POLARITY_G) then
323	         r <= REG_INIT_C after TPD_G;
324	      elsif rising_edge(clk) then
325	         r <= rin after TPD_G;
326	      end if;
327	   end process seq;
328	
329	   U_TxPipeline : entity surf.AxiStreamPipeline
330	      generic map (
331	         TPD_G          => TPD_G,
332	         RST_POLARITY_G => RST_POLARITY_G,
333	         RST_ASYNC_G    => RST_ASYNC_G,
334	         PIPE_STAGES_G  => 0)
335	      port map (
336	         axisClk     => clk,
337	         axisRst     => rst,
338	         sAxisMaster => txMaster,
339	         sAxisSlave  => txSlave,
340	         mAxisMaster => mAxisMaster,
341	         mAxisSlave  => mAxisSlave);
342	
343	   U_DeMux : entity surf.AxiStreamDeMux
344	      generic map (
345	         TPD_G          => TPD_G,
346	         RST_POLARITY_G => RST_POLARITY_G,
347	         RST_ASYNC_G    => RST_ASYNC_G,
348	         PIPE_STAGES_G  => 1,
349	         NUM_MASTERS_G  => 2)
350	      port map (
351	         -- Clock and reset
352	         axisClk         => clk,
353	         axisRst         => rst,
354	         -- Slave
355	         sAxisMaster     => mAxisMaster,
356	         sAxisSlave      => mAxisSlave,
357	         -- Masters
358	         mAxisMasters(0) => obIpv4Master,
359	         mAxisMasters(1) => localhostMaster,
360	         mAxisSlaves(0)  => obIpv4Slave,
361	         mAxisSlaves(1)  => localhostSlave);
362	
363	end rtl;
